const Database = require('better-sqlite3');
const { v4: uuidv4 } = require('uuid');
require('dotenv').config();

const db = new Database(process.env.DB_PATH || './data/simulator.db');

db.exec(`
  CREATE TABLE IF NOT EXISTS carriers (
    id TEXT PRIMARY KEY,
    name TEXT NOT NULL,
    person TEXT NOT NULL,
    phone TEXT,
    dirs TEXT NOT NULL DEFAULT '["UA","PL"]',
    vehicle_types TEXT NOT NULL DEFAULT '["Тент"]',
    reliability REAL DEFAULT 0.85,
    availability REAL DEFAULT 0.60,
    personality TEXT DEFAULT 'tough',
    nationality TEXT DEFAULT 'UA',
    active INTEGER DEFAULT 1,
    created_at TEXT DEFAULT (datetime('now'))
  )
`);

const existing = db.prepare("SELECT COUNT(*) as c FROM carriers").get();
if(existing.c > 0){
  console.log('Carriers already seeded: '+existing.c);
  process.exit(0);
}

const ins = db.prepare(`INSERT INTO carriers(id,name,person,phone,dirs,vehicle_types,reliability,availability,personality,nationality) VALUES(?,?,?,?,?,?,?,?,?,?)`);
const insertAll = db.transaction(arr=>{for(const c of arr)ins.run(uuidv4(),c.n,c.p,c.ph,JSON.stringify(c.d),JSON.stringify(c.t),c.r,c.a,c.pers,c.nat);});

